#!/usr/bin/env python3
"""
CI/CD pip install script for automated deployment pipeline.
Installs all requirements from requirements.txt with upgrade flag for latest versions.
"""

import subprocess
import sys
import os


def check_requirements_file(filepath="requirements.txt"):
    """Check if requirements file exists and is readable."""
    if not os.path.isfile(filepath):
        print(f"Error: {filepath} not found in {os.getcwd()}")
        sys.exit(1)
    if os.path.getsize(filepath) == 0:
        print(f"Warning: {filepath} is empty. No packages to install.")
        sys.exit(0)
    return filepath


def upgrade_pip():
    """Upgrade pip itself to the latest version."""
    print("=" * 60)
    print("Upgrading pip to latest version...")
    print("=" * 60)
    result = subprocess.run(
        [
            sys.executable, "-m", "pip", "install",
            "--upgrade", "pip"
        ],
        capture_output=True,
        text=True
    )
    if result.returncode != 0:
        print(f"Warning: Failed to upgrade pip: {result.stderr}")
    else:
        print("pip upgraded successfully.")
    print()


def install_requirements(filepath="requirements.txt"):
    """
    Install all packages from requirements.txt with --upgrade flag.
    Uses --no-cache-dir for clean installs and --upgrade for latest versions.
    Hash verification is not used for speed in CI/CD environments.
    """
    print("=" * 60)
    print(f"Installing requirements from {filepath}")
    print("Flags: --upgrade (latest versions), --no-cache-dir (clean install)")
    print("Hash verification: disabled for speed")
    print("=" * 60)
    print()

    # Display packages to be installed
    print("Packages to install:")
    print("-" * 40)
    with open(filepath, "r") as f:
        for line in f:
            line = line.strip()
            if line and not line.startswith("#"):
                print(f"  - {line}")
    print("-" * 40)
    print()

    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", filepath,
        "--upgrade",
        "--no-cache-dir",
        "--require-hashes=false" if False else "",  # noqa - hash verification disabled
    ]
    # Remove empty strings from command
    cmd = [c for c in cmd if c]

    # Build the actual command
    cmd = [
        sys.executable, "-m", "pip", "install",
        "-r", filepath,
        "--upgrade",
        "--no-cache-dir",
    ]

    print(f"Running: {' '.join(cmd)}")
    print()

    result = subprocess.run(
        cmd,
        text=True,
        stdout=subprocess.PIPE,
        stderr=subprocess.STDOUT
    )

    # Print output
    if result.stdout:
        print(result.stdout)

    if result.returncode != 0:
        print(f"Error: pip install failed with return code {result.returncode}")
        sys.exit(result.returncode)

    print()
    print("All requirements installed successfully.")
    return True


def verify_installation(filepath="requirements.txt"):
    """Verify that all required packages are installed."""
    print()
    print("=" * 60)
    print("Verifying installed packages...")
    print("=" * 60)

    result = subprocess.run(
        [sys.executable, "-m", "pip", "list", "--format=columns"],
        capture_output=True,
        text=True
    )

    if result.returncode == 0:
        print(result.stdout)
    else:
        print(f"Warning: Could not list installed packages: {result.stderr}")

    # Run pip check to verify dependencies are compatible
    print("Running dependency check...")
    check_result = subprocess.run(
        [sys.executable, "-m", "pip", "check"],
        capture_output=True,
        text=True
    )

    if check_result.returncode == 0:
        print("All dependencies are compatible.")
    else:
        print(f"Warning: Dependency issues found:\n{check_result.stdout}")
        # Don't exit on dependency warnings in CI/CD - just warn


def main():
    """Main entry point for CI/CD pip install script."""
    print("=" * 60)
    print("CI/CD Dependency Installation Script")
    print(f"Python: {sys.version}")
    print(f"Working Directory: {os.getcwd()}")
    print("=" * 60)
    print()

    # Allow custom requirements file path via command line argument
    requirements_file = sys.argv[1] if len(sys.argv) > 1 else "requirements.txt"

    # Step 1: Check requirements file exists
    check_requirements_file(requirements_file)

    # Step 2: Upgrade pip
    upgrade_pip()

    # Step 3: Install all requirements with upgrade flag
    install_requirements(requirements_file)

    # Step 4: Verify installation
    verify_installation(requirements_file)

    print()
    print("=" * 60)
    print("CI/CD dependency installation completed successfully!")
    print("=" * 60)


if __name__ == "__main__":
    main()